                    toastr.error('当前环境无法访问聊天消息接口');
                    return;
                }
                const lastId = getLastMessageId();
                if (lastId < 1) {
                    toastr.warning('没有可恢复的用户发言');
                    return;
                }
                const range = `0-${lastId}`;
                const users = getChatMessages(range, { role: 'user', hide_state: 'unhidden' });
                if (!users.length) {
                    toastr.warning('没有可恢复的用户发言');
                    return;
