                // 每次生成完成后都打开标签验证弹窗，由用户确认或回退
                openTagValidationDialog(filteredResult);
                return; // 等待用户点击确认或回退
            }
            catch (error) {
                console.error('❌ [App] 生成失败:', error);
                toastr.error('生成失败: ' + String(error));
                // 清理流式监听
                if (unsubscribeStream) {
                    try {
                        unsubscribeStream?.();
                    }
                    catch (e) {
                        // 忽略
